def find_first_greater(arr, target):
    if not arr:
        return -1

    left, right = 0, len(arr) - 1
    result = -1

    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] > target:
            result = mid
            right = mid - 1
        else:
            left = mid + 1

    return result

def merge_intervals(intervals):
    if not intervals:
        return []

    merged = [intervals[0]]
    for start, end in intervals[1:]:
        last_start, last_end = merged[-1]
        if start <= last_end:
            merged[-1][1] = max(last_end, end)
        else:
            merged.append([start, end])
    return merged

class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = {}
        self.order = []
        self.key_index = {}

    def _move_to_end(self, key: int) -> None:
        idx = self.key_index[key]
        del self.order[idx]
        self.order.append(key)
        self.key_index[key] = len(self.order) - 1
        for i in range(idx, len(self.order) - 1):
            self.key_index[self.order[i]] = i

    def get(self, key: int) -> int:
        if key not in self.cache:
            return -1
        self._move_to_end(key)
        return self.cache[key]

    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            self.cache[key] = value
            self._move_to_end(key)
            return
        if len(self.cache) == self.capacity:
            lru_key = self.order.pop(0)
            del self.cache[lru_key]
            del self.key_index[lru_key]
            for i in range(len(self.order)):
                self.key_index[self.order[i]] = i
        self.cache[key] = value
        self.order.append(key)
        self.key_index[key] = len(self.order) - 1

def is_valid_parentheses(s):
    stack = []
    mapping = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in mapping:
            top_element = stack.pop() if stack else '#'
            if mapping[char] != top_element:
                return False
        else:
            stack.append(char)
    return not stack

def compress_string(s):
    if not s:
        return s

    compressed = []
    count = 1

    for i in range(1, len(s)):
        if s[i] == s[i-1]:
            count += 1
        else:
            compressed.append(s[i-1] + str(count))
            count = 1

    compressed.append(s[-1] + str(count))

    compressed_str = ''.join(compressed)

    return compressed_str if len(compressed_str) < len(s) else s

